import React, {useEffect, useState} from "react";
import styled, {keyframes} from 'styled-components';
import {slideOutUp,slideOutDown} from 'react-animations';


const Cover = () => {
    const SlideOutUp = styled.div`animation: 2s ${keyframes`${slideOutUp}`} 1 `;
    const SlideOutDown = styled.div`animation: 2s ${keyframes`${slideOutDown}`} 1 `;
    const [isButtonClicked,SetButtonClick] = useState(
        {
            web:false,
            software:false
        }
    );

    useEffect(()=>{
        if(isButtonClicked.web===true)
        {
            alert("WEB")
        } else if(isButtonClicked.software===true)
        {
            alert("SOFTWARE")
        }
    });

    return (
        <div className="ui segments">
            {/*{isButtonClicked.web & (*/}
            <SlideOutUp>
                <div className="ui segment grid-top top-cover"/>
            </SlideOutUp>
            // )
            // }
            {/*{!isButtonClicked.web & (*/}
            {/*    <div className="ui segment grid-top top-cover"/>*/}

            {/*// )*/}
            {/*// }*/}
            <div className="ui segment choices">
                <button className="circular ui grid-top inverted right labeled icon purple button" onClick={()=>SetButtonClick({web:true})}><i className="right arrow icon"></i>Front/Back-end Developer</button>
                <button className="circular ui grid-bottom inverted right labeled icon purple button" onClick={()=>SetButtonClick({software:true})}><i className="right arrow icon"></i>Software Engineer</button>
            </div>
            {isButtonClicked.software & (
                <SlideOutDown className="bottom-cover-div">
                    <div className="ui segment grid-bottom bottom-cover"></div>
                </SlideOutDown>
            )
            }
            {/*{!isButtonClicked.software & (*/}
                <div className="bottom-cover-div">
                    <div className="ui segment grid-bottom bottom-cover"></div>
                </div>
            {/*)*/}

            {/*}*/}
        </div>
    )
};
export default Cover;
